SELECT COUNT(*) > 0
FROM reviews
WHERE place_id = #{placeId} AND user_id = #{userId}

SELECT r.review_id, r.place_id, r.user_id, u.nickname,
       r.content, r.rating, r.created_at
FROM reviews r
         JOIN users u ON r.user_id = u.user_id
WHERE r.place_id = #{placeId}
ORDER BY r.created_at DESC
LIMIT #{limitSize}
    OFFSET #{offset}

SELECT COUNT(*) > 0
FROM reviews
WHERE review_id = #{reviewId} AND place_id = #{placeId}

mapper.update:
UPDATE reviews
SET content = #{content},
    rating  = #{rating}
WHERE review_id = #{reviewId}
